const item = $input.first().json || {};
const staticData = $getWorkflowStaticData('global');

const isError = !!(item.error && typeof item.error === 'object' && item.error.message);

if (isError) {
  staticData.lastDeadMansSwitchFailure = item.error.message;
} else {
  delete staticData.lastDeadMansSwitchFailure;
}

return [{
  json: {
    dmsFailure: isError,
    dmsOk: !isError,
    dmsErrorMessage: isError ? item.error.message : '',
    dmsFiredThisCycle: isError
  }
}];

const item = $input.first().json || {};
const staticData = $getWorkflowStaticData('global');

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function truncateRaw(text, max) {
  var value = String(text || '');
  return value.length <= max ? value : value.slice(0, max - 1) + '…';
}

const orphanAlertKey = 'orphan_alert_memory';
const orphanMemory = staticData[orphanAlertKey] || {};
const ORPHAN_REALERT_MS = 60 * 60 * 1000; // 1 hour

if (item.error || (typeof item === 'object' && item.error)) {
  staticData.orphanUncertainty = {
    timestamp: new Date().toISOString(),
    reason: item.error?.message || 'n8n API unreachable during orphan detection'
  };
  return [{
    json: {
      apiError: true,
      hasOrphans: false,
      hasAlertableOrphans: false,
      orphans: [],
      orphanCount: 0,
      alertableOrphanCount: 0,
      orphanArray: '[]',
      orphanAlertText: '',
      orphanState: 'api_error',
      errorMessage: item.error?.message || 'API unreachable'
    }
  }];
}

const data = item.data || item;
const arr = Array.isArray(data) ? data : (Array.isArray(data.data) ? data.data : []);

if (!Array.isArray(arr)) {
  staticData.orphanUncertainty = {
    timestamp: new Date().toISOString(),
    reason: 'Unexpected n8n API response shape during orphan detection'
  };
  return [{
    json: {
      apiError: true,
      hasOrphans: false,
      hasAlertableOrphans: false,
      orphans: [],
      orphanCount: 0,
      alertableOrphanCount: 0,
      orphanArray: '[]',
      orphanAlertText: '',
      orphanState: 'api_error',
      errorMessage: 'Unexpected n8n API response shape'
    }
  }];
}

const healthData = (() => {
  try { return $('System Status').first().json || {}; } catch (e) { return {}; }
})();

if (arr.length === 0) {
  const isActiveSystem = healthData.circuit_status === 'open' || healthData.circuit_status === 'half_open' || !!healthData.error;
  if (isActiveSystem) {
    staticData.orphanUncertainty = {
      timestamp: new Date().toISOString(),
      reason: 'API returned 0 running executions during active/degraded system'
    };
    return [{ json: { apiError: false, hasOrphans: false, hasAlertableOrphans: false, orphans: [], orphanCount: 0, alertableOrphanCount: 0, orphanArray: '[]', orphanAlertText: '', orphanState: 'uncertain', uncertainResult: true } }];
  }
  delete staticData.orphanUncertainty;
  return [{ json: { apiError: false, hasOrphans: false, hasAlertableOrphans: false, orphans: [], orphanCount: 0, alertableOrphanCount: 0, orphanArray: '[]', orphanAlertText: '', orphanState: 'none' } }];
}

const now = Date.now();
const threshold = 30 * 60 * 1000;
const MONITORING_WORKFLOW_IDS = [
  $env.SUPERVISOR_WORKFLOW_ID || '',
  $env.HEARTBEAT_WORKFLOW_ID || '',
  $env.RETENTION_WORKFLOW_ID || ''
].filter(Boolean).map(String);

const LONG_RUNNING_IDS = String($env.LONG_RUNNING_WORKFLOW_IDS || '')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

const excludeIds = new Set([...MONITORING_WORKFLOW_IDS, ...LONG_RUNNING_IDS]);

const orphans = arr.filter(exec => {
  const startedAtRaw = exec.startedAt || exec.createdAt;
  const startedAt = new Date(startedAtRaw).getTime();
  if (!startedAt || Number.isNaN(startedAt)) return false;
  return (now - startedAt) > threshold && !excludeIds.has(String(exec.workflowId));
}).map(exec => {
  const baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';
  return {
    executionId: String(exec.id),
    workflowId: String(exec.workflowId || 'unknown'),
    workflowName: exec.workflowName || exec.workflow?.name || 'unknown',
    startedAt: exec.startedAt || exec.createdAt,
    runningMinutes: Math.round((now - new Date(exec.startedAt || exec.createdAt).getTime()) / 60000),
    executionUrl: baseUrl + '/executions/' + String(exec.id)
  };
});

if (orphans.length === 0) {
  delete staticData.orphanUncertainty;
}

const alertableOrphans = orphans.filter(o => {
  var last = orphanMemory[o.executionId] || 0;
  return (now - last) > ORPHAN_REALERT_MS;
});

for (var ao of alertableOrphans) {
  orphanMemory[ao.executionId] = now;
}

for (var [id, ts] of Object.entries(orphanMemory)) {
  if (now - ts > 24 * 60 * 60 * 1000) delete orphanMemory[id];
}
staticData[orphanAlertKey] = orphanMemory;

var displayOrphans = alertableOrphans
  .sort(function(a, b) { return b.runningMinutes - a.runningMinutes; })
  .slice(0, 5);
var omittedCount = Math.max(alertableOrphans.length - 5, 0);

var orphanArray = orphans.map(function(o) {
  return {
    executionId: o.executionId,
    workflowId: o.workflowId,
    workflowName: o.workflowName,
    runningMinutes: o.runningMinutes,
    orphanCount: orphans.length
  };
});

var orphanAlertText = '';
if (displayOrphans.length > 0) {
  var baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';
  orphanAlertText = displayOrphans.map(function(o) {
    return '<b>Execution:</b> ' + baseUrl + '/executions/' + o.executionId + '
<b>Workflow:</b> ' + htmlEscape(truncateRaw(o.workflowName, 100)) + '
<b>Running:</b> ' + o.runningMinutes + ' minutes';
  }).join('
---
');
  if (omittedCount > 0) {
    orphanAlertText += '

…and ' + omittedCount + ' more orphan(s) omitted.';
  }
  orphanAlertText = '⚠️ <b>ORPHAN EXECUTION DETECTED</b>

' + orphanAlertText + '

<b>Total Orphans:</b> ' + alertableOrphans.length + '
<b>Timestamp:</b> ' + new Date().toLocaleString('en-PH', { timeZone: 'Asia/Manila', year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
}

return [{
  json: {
    apiError: false,
    hasOrphans: orphans.length > 0,
    hasAlertableOrphans: alertableOrphans.length > 0,
    orphanCount: orphans.length,
    alertableOrphanCount: alertableOrphans.length,
    orphanArray: JSON.stringify(orphanArray),
    orphanAlertText: orphanAlertText,
    orphanState: 'found'
  }
}];

const crypto = require('crypto');
const item = $input.first().json || {};
const staticData = $getWorkflowStaticData('global');
const expectedIds = String($env.CRITICAL_WORKFLOW_IDS || '')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

const baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';

if (expectedIds.length === 0) {
  delete staticData.activationCheckUncertain;
  return [{ json: { activationConfigured: false, activationIssue: false, hasDeactivated: false, activationUncertain: false, shouldAlertActivation: false, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: 0, activationMessage: 'CRITICAL_WORKFLOW_IDS not configured' } }];
}

var activationIssue = false;
var activationUncertain = false;
var hasDeactivated = false;
var deactivatedIds = [];
var deactivatedUrls = [];
var activeCount = 0;

if (item.error && item.error.message) {
  activationIssue = true;
  activationUncertain = true;
  staticData.activationCheckUncertain = {
    timestamp: new Date().toISOString(),
    reason: item.error.message
  };
} else {
  const data = item.data || item;
  const arr = Array.isArray(data) ? data : (Array.isArray(data.data) ? data.data : []);

  if (!Array.isArray(arr)) {
    activationIssue = true;
    activationUncertain = true;
    staticData.activationCheckUncertain = {
      timestamp: new Date().toISOString(),
      reason: 'Unexpected active workflows API response shape'
    };
  } else {
    const activeIds = new Set(arr.map(w => String(w.id)));
    deactivatedIds = expectedIds.filter(id => !activeIds.has(String(id)));
    deactivatedUrls = deactivatedIds.map(id => baseUrl + '/workflow/' + id);
    activeCount = activeIds.size;

    if (deactivatedIds.length > 0) {
      activationIssue = true;
      activationUncertain = false;
      hasDeactivated = true;
      delete staticData.activationCheckUncertain;
    } else {
      activationIssue = false;
      activationUncertain = false;
      hasDeactivated = false;
      delete staticData.activationCheckUncertain;
    }
  }
}

var activationStateHash = crypto.createHash('sha1').update(JSON.stringify({
  activationIssue: activationIssue,
  activationUncertain: activationUncertain,
  deactivatedIds: deactivatedIds.sort()
})).digest('hex');

var lastActivationHash = staticData.lastActivationAlertHash || '';
var activationChanged = activationStateHash !== lastActivationHash;
var shouldAlertActivation = activationIssue && activationChanged;

if (shouldAlertActivation) {
  staticData.lastActivationAlertHash = activationStateHash;
}

return [{
  json: {
    activationConfigured: true,
    activationIssue: activationIssue,
    hasDeactivated: hasDeactivated,
    activationUncertain: activationUncertain,
    shouldAlertActivation: shouldAlertActivation,
    deactivatedIds: deactivatedIds,
    deactivatedUrls: deactivatedUrls,
    activeCount: activeCount,
    expectedCount: expectedIds.length,
    activationMessage: activationIssue
      ? (activationUncertain ? 'Activation check uncertain' : deactivatedIds.length + ' critical workflow(s) inactive')
      : 'All critical workflows active'
  }
}];

