const crypto = require('crypto');

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function truncateRaw(text, max) {
  var value = String(text || '');
  return value.length <= max ? value : value.slice(0, max - 1) + '…';
}

function clampTelegramHtml(text, max) {
  max = max || 3900;
  var value = String(text || '');
  if (value.length <= max) return value;
  var note = '

⚠️ <i>Message truncated</i>';
  return value.substring(0, max - note.length) + note;
}

const statusItem = (() => {
  try { return $('System Status').first().json || {}; } catch(e) { return {}; }
})();
const activationItem = (() => {
  try { return $('Detect Activation State').first().json || {}; } catch(e) { return {}; }
})();
const dmsItem = (() => {
  try { return $('Check DMS Result').first().json || {}; } catch(e) { return {}; }
})();
const orphanItem = (() => {
  try { return $('Detect Orphans').first().json || {}; } catch(e) { return {}; }
})();
const staticData = $getWorkflowStaticData('global');

const isDbError = !!(statusItem.error && typeof statusItem.error === 'object' && statusItem.error.message);
const cs = isDbError ? 'unknown' : (statusItem.circuit_status || 'unknown');
const ec = isDbError ? 0 : (parseInt(statusItem.error_count, 10) || 0);
const errHour = isDbError ? 0 : (parseInt(statusItem.errors_last_hour, 10) || 0);
const err24h = isDbError ? 0 : (parseInt(statusItem.errors_last_24h, 10) || 0);
const lastHeartbeatAt = statusItem.last_heartbeat_at || null;

let topSources = [];
try {
  const raw = statusItem.top_error_sources;
  if (typeof raw === 'string') topSources = JSON.parse(raw);
  else if (Array.isArray(raw)) topSources = raw;
} catch(e) { topSources = []; }

const circuitIcon = cs === 'closed' ? '🟢' : cs === 'half_open' ? '🟡' : cs === 'open' ? '🔴' : '⚪';

const dmsFiredThisCycle = dmsItem.dmsFiredThisCycle || false;
const cachedCount = (staticData.eventFailures && staticData.eventFailures.length) || 0;
const droppedCount = staticData.droppedCacheCount || 0;

var hasOrphans = orphanItem.hasOrphans || false;
var orphanCount = orphanItem.orphanCount || 0;
var orphanState = orphanItem.orphanState || 'unknown';

var isDegraded = isDbError || cs === 'open' || cs === 'half_open' || cachedCount > 0
  || !!staticData.lastDeadMansSwitchFailure || orphanState === 'uncertain'
  || !!staticData.activationCheckUncertain || !!activationItem.hasDeactivated
  || hasOrphans;

var isCritical = isDbError || cs === 'open';
var previousVerdict = staticData.lastVerdict || 'HEALTHY';
var currentVerdict = isCritical ? 'CRITICAL' : isDegraded ? 'DEGRADED' : 'HEALTHY';
var isRecovery = previousVerdict !== 'HEALTHY' && currentVerdict === 'HEALTHY';

var recoveryDetails = [];
if (isRecovery && staticData.lastDegradedReasons) {
  var prev = staticData.lastDegradedReasons;
  if (prev.circuitOpen && cs === 'closed') recoveryDetails.push('circuit closed');
  if (prev.dmsFailure && !staticData.lastDeadMansSwitchFailure) recoveryDetails.push('DMS restored');
  if (prev.activationIssue && !activationItem.activationIssue) recoveryDetails.push('workflows reactivated');
  if (prev.dbError && !isDbError) recoveryDetails.push('database reconnected');
  if (prev.cachedFailures && cachedCount === 0) recoveryDetails.push('cache cleared');
  if (prev.hasOrphans && !hasOrphans) recoveryDetails.push('orphans resolved');
}

if (isDegraded) {
  staticData.lastDegradedReasons = {
    circuitOpen: cs === 'open',
    dmsFailure: !!staticData.lastDeadMansSwitchFailure,
    activationIssue: !!activationItem.activationIssue,
    dbError: isDbError,
    cachedFailures: cachedCount > 0,
    hasOrphans: hasOrphans
  };
} else {
  delete staticData.lastDegradedReasons;
}

staticData.lastVerdict = currentVerdict;

const verdict = isCritical ? '🔴 CRITICAL' : isDegraded ? '🟡 DEGRADED' : '🟢 HEALTHY';

let topSourcesLine = '';
if (topSources.length > 0) {
  topSourcesLine = '

🏆 <b>Top Sources (24h):</b>';
  topSources.forEach(function(src, i) {
    topSourcesLine += '
' + (i + 1) + '. ' + htmlEscape(truncateRaw(src.workflow_name, 100)) + ' — ' + src.error_count + ' errors' + (src.errors_1h > 0 ? ' (' + src.errors_1h + ' in 1h)' : '');
  });
}

const recoveryBanner = isRecovery
  ? '✅ <b>RECOVERED</b> — System returned to HEALTHY from ' + previousVerdict
    + (recoveryDetails.length > 0 ? ' (' + recoveryDetails.join(', ') + ')' : '')
    + '

'
  : '';

let orphanIcon = orphanState === 'found' ? '🔴'
  : orphanState === 'uncertain' ? '🟡'
  : orphanState === 'api_error' ? '🔴'
  : orphanState === 'none' ? '🟢'
  : '⚪';

let orphanText = orphanState === 'found' ? orphanCount + ' detected'
  : orphanState === 'uncertain' ? 'uncertain'
  : orphanState === 'api_error' ? 'API unreachable'
  : orphanState === 'none' ? 'none'
  : 'unknown';

let emergencyNote = '';
if (cachedCount > 0) {
  emergencyNote = '
🚨 <b>Heartbeat Local Cache:</b> ' + cachedCount + ' failed event(s)';
  if (droppedCount > 0) emergencyNote += ' (' + droppedCount + ' dropped due to overflow)';
}

let dmsNote = '';
if (staticData.lastDeadMansSwitchFailure && !dmsFiredThisCycle) {
  dmsNote = '
⚠️ <b>DMS Failure:</b> <code>' + htmlEscape(truncateRaw(String(staticData.lastDeadMansSwitchFailure), 200)) + '</code>';
}

let orphanNote = '';
if (orphanState === 'uncertain') {
  orphanNote = '
⚠️ <b>Orphan Uncertain:</b> ' + htmlEscape(truncateRaw(staticData.orphanUncertainty?.reason || '', 200));
}

let activationNote = '';
if (staticData.activationCheckUncertain) {
  activationNote = '
⚠️ <b>Activation Uncertain:</b> ' + htmlEscape(truncateRaw(staticData.activationCheckUncertain.reason, 200));
} else if (activationItem.hasDeactivated) {
  activationNote = '
⚠️ <b>Inactive Critical:</b> ' + activationItem.deactivatedUrls.map(u => '<a href="' + u + '">' + u + '</a>').join(', ');
} else if (activationItem.activationConfigured) {
  activationNote = '
✅ <b>Workflows:</b> ' + activationItem.expectedCount + '/' + activationItem.expectedCount + ' active';
}

const dbNote = isDbError ? '
🔴 <b>DATABASE UNREACHABLE</b>' : '';

var prevHourErrors = staticData.prevCycleErrorsHour || 0;
var direction = errHour > prevHourErrors ? '📈' : errHour < prevHourErrors ? '📉' : '➡️';
staticData.prevCycleErrorsHour = errHour;

var trend = errHour >= 3 ? '🔴 spike ' + direction : err24h >= 10 ? '🟡 elevated ' + direction : '🟢 stable';

const text = recoveryBanner + '💓 <b>SUPERVISOR — ' + verdict + '</b>

'
  + circuitIcon + ' <b>Circuit:</b> ' + cs + ' (' + ec + '/5)
'
  + (dmsItem.dmsOk ? '🟢' : '🔴') + ' <b>DMS:</b> ' + (dmsItem.dmsOk ? 'ok' : 'FAILED') + '
'
  + (activationItem.activationConfigured ? (activationItem.activationIssue ? '🔴' : '🟢') + ' <b>Workflows:</b> ' + (activationItem.activationIssue ? activationItem.activationMessage : activationItem.expectedCount + '/' + activationItem.expectedCount + ' active') : '⚪ <b>Workflows:</b> not configured') + '
'
  + orphanIcon + ' <b>Orphans:</b> ' + orphanText + '
'
  + '📊 <b>Trend:</b> ' + trend + '
'
  + '
<b>Errors:</b> ' + errHour + ' (1h) · ' + err24h + ' (24h)'
  + topSourcesLine
  + dbNote + emergencyNote + dmsNote + orphanNote + activationNote
  + '

<b>Timestamp:</b> ' + new Date().toLocaleString('en-PH', { timeZone: 'Asia/Manila', year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });

const stableErrHour = Math.floor(errHour / 3) * 3;
const stableErr24h = Math.floor(err24h / 5) * 5;
const stableTopSources = topSources.map(function(s) {
  return s.workflow_name + ':' + (Math.floor(s.error_count / 3) * 3);
}).join(',');

const hashInput = cs + ':' + ec + ':' + stableErrHour + ':' + stableErr24h + ':' + isDbError + ':' + cachedCount + ':' + droppedCount + ':' + !!staticData.lastDeadMansSwitchFailure + ':' + orphanState + ':' + orphanCount + ':' + !!staticData.activationCheckUncertain + ':' + !!activationItem.hasDeactivated + ':' + (activationItem.deactivatedIds?.join(',') || '') + ':' + stableTopSources;
const messageHash = crypto.createHash('md5').update(hashInput).digest('hex');
const lastSentHash = staticData.lastHeartbeatHash || '';
const isDuplicate = messageHash === lastSentHash;

const now = new Date();
const currentHourKey = now.toISOString().slice(0, 13);
const lastHealthyHourSent = staticData.lastHealthyHourSent || '';

let shouldSend = false;
let sendReason = 'suppressed';

if (isDbError) {
  shouldSend = true;
  sendReason = 'database_unreachable';
} else if (isRecovery) {
  shouldSend = true;
  sendReason = 'recovery_to_healthy';
} else if (isDegraded && !isDuplicate) {
  shouldSend = true;
  sendReason = 'degraded_state_changed';
} else if (!isDegraded && now.getMinutes() < 5 && lastHealthyHourSent !== currentHourKey) {
  shouldSend = true;
  sendReason = 'hourly_healthy_pulse';
}

const finalText = clampTelegramHtml(text);

return [{
  json: {
    text: finalText,
    messageHash: messageHash,
    isDuplicate: isDuplicate,
    isDegraded: isDegraded,
    isCritical: isCritical,
    verdict: verdict,
    shouldSend: shouldSend,
    sendReason: sendReason,
    dbError: isDbError,
    circuit_status: cs,
    error_count: ec,
    errors_last_hour: errHour,
    errors_last_24h: err24h,
    emergency_cache_count: cachedCount,
    dropped_cache_count: droppedCount,
    dms_failure_active: !!staticData.lastDeadMansSwitchFailure,
    orphan_uncertain: orphanState === 'uncertain',
    activation_uncertain: !!staticData.activationCheckUncertain,
    activation_issue: !!activationItem.activationIssue,
    activation_deactivated_ids: activationItem.deactivatedIds || [],
    currentHourKey: currentHourKey
  }
}];

const staticData = $getWorkflowStaticData('global');
const evalData = (() => {
  try { return $('Evaluate System Health').first().json; } catch(e) { return {}; }
})();

staticData.lastHeartbeatHash = evalData.messageHash || '';

if (!evalData.isDegraded && evalData.currentHourKey) {
  staticData.lastHealthyHourSent = evalData.currentHourKey;
}

staticData.eventFailures = [];
staticData.droppedCacheCount = 0;
staticData.lastSuccessfulHeartbeatAt = new Date().toISOString();

return [{ json: { cacheCleared: true, hashUpdated: true, lastSuccessfulHeartbeatAt: staticData.lastSuccessfulHeartbeatAt } }];

const staticData = $getWorkflowStaticData('global');
const item = $input.first().json || {};
if (!staticData.eventFailures) staticData.eventFailures = [];
staticData.eventFailures.push({
  timestamp: new Date().toISOString(),
  traceId: item.traceId || 'unknown',
  eventType: 'alert_failed',
  source: 'Heartbeat Monitor',
  workflowName: 'Heartbeat Monitor',
  failedNode: item.failedNode || 'unknown',
  reason: item.error?.message || 'Telegram, Postgres, or HTTP delivery failed — cached in Heartbeat local cache'
});
if (staticData.eventFailures.length > 50) {
  staticData.droppedCacheCount = (staticData.droppedCacheCount || 0) + (staticData.eventFailures.length - 50);
  staticData.eventFailures = staticData.eventFailures.slice(-50);
}
return [{ json: { cached: true, count: staticData.eventFailures.length, droppedCacheCount: staticData.droppedCacheCount || 0 } }];
